Here's how to implement this in .NET MAUI Shell:

**EditProductPage.xaml**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/clr-runtime"
             x:Class="MyApp.EditProductPage"
             Shell.BackButtonBehavior="{StaticResource CancelBackButton}">

    <ContentPage.Resources>
        <BackButtonBehavior x:Key="CancelBackButton"
                            TextOverride="Cancel"
                            Command="{Binding BackCommand}" />
    </ContentPage.Resources>

    <!-- your form here -->
</ContentPage>
```

**EditProductPage.xaml.cs**
```csharp
public partial class EditProductPage : ContentPage
{
    private bool _hasUnsavedChanges;

    public EditProductPage()
    {
        InitializeComponent();
        BindingContext = this;
        BackCommand = new Command(OnBackRequested);
    }

    public ICommand BackCommand { get; }

    private async void OnBackRequested()
    {
        if (_hasUnsavedChanges)
        {
            bool leave = await DisplayAlert(
                "Unsaved Changes",
                "You have unsaved changes. Discard and go back?",
                "Discard", "Stay");

            if (!leave)
                return; // cancel navigation
        }

        await Shell.Current.GoBackAsync();
    }

    // Intercept hardware/gesture back (Android, swipe-back)
    protected override bool OnBackButtonPressed()
    {
        if (_hasUnsavedChanges)
        {
            // Fire-and-forget the async dialog; return true to cancel immediate nav
            MainThread.BeginInvokeOnMainThread(async () => await OnBackRequested());
            return true; // suppress default back
        }

        return base.OnBackButtonPressed();
    }
}
```

**Key points:**

- `Shell.BackButtonBehavior` with `TextOverride="Cancel"` replaces the back arrow with a "Cancel" label and routes taps through your command.
- `OnBackButtonPressed()` intercepts the Android hardware/gesture back button — return `true` to cancel navigation.
- iOS swipe-back gesture isn't intercepted by `OnBackButtonPressed`. To fully block it, disable it via a platform-specific handler or set `Shell.PresentationMode="ModalAnimated"` for the page.
